// Find character index in font data
static inline int16_t ChineseCharToIndex(uint16_t unicode) {
    for (uint16_t i = 0; i < sizeof(gChineseCharMap) / sizeof(gChineseCharMap[0]); i++) {
        if (gChineseCharMap[i].unicode == unicode) {
            return gChineseCharMap[i].index;
        }
    }
    return -1;  // Character not found
}

